let ControlByte = 0;
ControlByte = ControlByte + (flow.get("CB_TR") || 0) * 1;
ControlByte = ControlByte + (flow.get("CB_RA") || 0) * 2;
ControlByte = ControlByte + (flow.get("CB_IR") || 0) * 4;
ControlByte = ControlByte + (flow.get("CB_SC") || 0) * 8;
ControlByte = ControlByte + (flow.get("CB_RC") || 0) * 128;

msg.payload = [];

msg.payload[0] = ControlByte;
return msg;

//  Integer value received as input (diStatB for status byte)
//let inputValue = Number(msg.payload);
let diStatB = Number(msg.payload);

// check the input format
if (!Number.isInteger(diStatB)) {
    node.warn("msg.payload isn't a valide integer");
    return Array(16).fill(null);
}

// force the value to remain 16 bits.
diStatB = diStatB & 0xFFFF;

let diPreviousStatB = flow.get("storedStatusByte");
let outputs = Array(16).fill(null);  // key to handling multiple outputs in Node-RED

if (diPreviousStatB !== diStatB) {
    flow.set("storedStatusByte", diStatB);
    let In_Lenght = 0;

    for (let i = 0; i < 16; i++) {
        let bitValue = (diStatB >> i) & 0x01;

        switch(i){
            case 0:
                flow.set("SB_TA", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_TA, transmit accepted"
                };
                break;
            case 1:
                flow.set("SB_RR", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_RR, receive request"
                };
                break;
            case 2:
                flow.set("SB_IA", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_IA, init accepted"
                };
                break;
            case 3:
                flow.set("SB_RX_ERR", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_RX_ERR, receive error"
                };
                break;
            case 4:
                flow.set("SB_RX_BUF_F", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_RX_BUF_F, RX buffer full"
                };
                break;
            case 5:
                flow.set("SB_TX_BUF_F", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_TX_BUF_F, TX buffer full"
                };
                break;
            case 6:
                flow.set("SB_GEN_ERR", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_GEN_ERR, general error"
                };
                break;
            case 7:
                flow.set("SB_RC", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_RC, register communication"
                };
                break;
            case 8:
                In_Lenght = In_Lenght + (bitValue * 1);
                break;
            case 9:
                In_Lenght = In_Lenght + (bitValue * 2);
                break;
            case 10:
                In_Lenght = In_Lenght + (bitValue * 4);
                break;
            case 11:
                In_Lenght = In_Lenght + (bitValue * 8);
                break;
            case 12:
                In_Lenght = In_Lenght + (bitValue * 16);
                break;
            case 13:
                In_Lenght = In_Lenght + (bitValue * 32);
                break;
            case 14:
                flow.set("SB_BUF_E", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_BUF_E, buffer empty"
                };
                break;
            case 15:
                flow.set("SB_CTS", bitValue);
                outputs[i] = {
                    payload: bitValue,
                    bit: i,
                    topic: "SB_CTS, clear to send"
                };
                break;
        }
        flow.set("SB_IL", In_Lenght);
    }
} else {
    outputs[0] = {
        payload: diStatB,
        topic: "unchanged_value"
    };
}

return outputs;

